-- Minimal subset of the macOS WhatsApp Desktop Core Data schema.
-- Only columns the importer reads are present.

CREATE TABLE ZWACHATSESSION (
    Z_PK INTEGER PRIMARY KEY,
    ZSESSIONTYPE INTEGER,
    ZARCHIVED INTEGER,
    ZUNREADCOUNT INTEGER,
    ZLASTMESSAGEDATE REAL,
    ZCONTACTJID VARCHAR,
    ZPARTNERNAME VARCHAR,
    ZGROUPINFO INTEGER
);

CREATE TABLE ZWAGROUPINFO (
    Z_PK INTEGER PRIMARY KEY,
    ZCHATSESSION INTEGER,
    ZCREATIONDATE REAL,
    ZOWNERJID VARCHAR
);

CREATE TABLE ZWAGROUPMEMBER (
    Z_PK INTEGER PRIMARY KEY,
    ZCHATSESSION INTEGER,
    ZISADMIN INTEGER,
    ZMEMBERJID VARCHAR
);

CREATE TABLE ZWAMESSAGE (
    Z_PK INTEGER PRIMARY KEY,
    ZCHATSESSION INTEGER,
    ZSTANZAID VARCHAR,
    ZFROMJID VARCHAR,
    ZTOJID VARCHAR,
    ZPUSHNAME VARCHAR,
    ZISFROMME INTEGER,
    ZMESSAGEDATE REAL,
    ZMESSAGETYPE INTEGER,
    ZTEXT VARCHAR,
    ZPARENTMESSAGE INTEGER,
    ZMEDIAITEM INTEGER
);

CREATE TABLE ZWAMEDIAITEM (
    Z_PK INTEGER PRIMARY KEY,
    ZMESSAGE INTEGER,
    ZFILESIZE INTEGER,
    ZMOVIEDURATION INTEGER,
    ZMEDIALOCALPATH VARCHAR
);

CREATE TABLE ZWAPROFILEPUSHNAME (
    Z_PK INTEGER PRIMARY KEY,
    ZJID VARCHAR,
    ZPUSHNAME VARCHAR
);
